mapper.select:
SELECT
    COUNT(*)                                                          AS totalCalls,
    COALESCE(AVG(total_latency_ms), 0)                                AS avgLatencyMs,
    COALESCE(SUM(CASE WHEN status = 'ERROR' THEN 1 ELSE 0 END), 0)    AS errorCalls
FROM ai_trace
WHERE deleted = 0

    AND tenant_id = #{tenantId}


    AND create_time >= #{start}


    AND create_time < #{end}
